import{_ as a,o as s,c as l,a5 as i}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：UPS 参数保存触发策略（parameter save scheduler）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：UPS 参数保存触发策略（parameter save scheduler）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0036-ups-parameter-save-scheduler.html` 的源稿和补充资料。它只讨论教学用触发策略，不包含公司内部保存策略、Flash 地址、客户项目参数、内部磨损均衡算法或真实产品掉电保护方案。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-parameter-save-scheduler.md","filePath":"content/power/concepts/embedded/ups-parameter-save-scheduler.md","lastUpdated":null}'),t={name:"content/power/concepts/embedded/ups-parameter-save-scheduler.md"};function r(d,e,o,c,n,p){return s(),l("div",null,[...e[0]||(e[0]=[i(`<h1 id="概念-ups-参数保存触发策略-parameter-save-scheduler" tabindex="-1">概念：UPS 参数保存触发策略（parameter save scheduler） <a class="header-anchor" href="#概念-ups-参数保存触发策略-parameter-save-scheduler" aria-label="Permalink to &quot;概念：UPS 参数保存触发策略（parameter save scheduler）&quot;">​</a></h1><p>本页是 <code>lessons/0036-ups-parameter-save-scheduler.html</code> 的源稿和补充资料。它只讨论教学用触发策略，不包含公司内部保存策略、Flash 地址、客户项目参数、内部磨损均衡算法或真实产品掉电保护方案。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>参数保存触发策略（parameter save scheduler）决定“参数被改了以后，什么时候真正写入非易失存储（non-volatile memory / NVM）”。它连接上一节的参数保存（parameter storage）模块，但不等于保存格式本身。</p><p>本课只讲一个概念：通信或本地逻辑修改参数后，先置位脏标志（dirty flag），再经过延时提交（delayed commit）和最小保存间隔（minimum save interval）判断，最后才触发一次 NVM 保存。</p><h2 id="为什么-ups-需要它" tabindex="-1">为什么 UPS 需要它 <a class="header-anchor" href="#为什么-ups-需要它" aria-label="Permalink to &quot;为什么 UPS 需要它&quot;">​</a></h2><p>如果每次参数写入都立刻执行 Flash 擦写（Flash erase/write），会带来三个问题：</p><ul><li>保存次数过多，增加 NVM 磨损风险。</li><li>多个参数连续写入时，可能产生多次没有必要的保存。</li><li>参数写入路径和保存路径耦合太紧，通信处理、状态机和存储驱动会变得难读。</li></ul><p>UPS 参数管理更需要“可解释的保存时机”：哪些写入发生了、什么时候被合并、最终保存了几次。这些证据适合用仿真波形和 C 代码输出向导师提问。</p><h2 id="物理直觉" tabindex="-1">物理直觉 <a class="header-anchor" href="#物理直觉" aria-label="Permalink to &quot;物理直觉&quot;">​</a></h2><p>脏标志像便签上的“这页改过了”。延时提交像等你停止连续修改后再拍照存档。最小保存间隔像规定“就算又改了，也不能太频繁地拿橡皮和钢笔重写同一页”，避免把存储器当成 RAM 一样频繁写。</p><p>本课的例子里，0 ms 和 20 ms 连续两次参数写入，只产生一次 80 ms 的 NVM 保存。这样可以看清“多次写入合并成一次保存”的主线。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><p>设：</p><ul><li><code>dirty</code>：是否有未保存参数。</li><li><code>last_change_ms</code>：最近一次参数变化时间。</li><li><code>last_save_ms</code>：最近一次保存时间。</li><li><code>commit_delay_ms</code>：延时提交时间。</li><li><code>minimum_save_interval_ms</code>：最小保存间隔。</li></ul><p>保存触发条件：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>should_save =</span></span>
<span class="line"><span>    dirty == 1</span></span>
<span class="line"><span>    and now_ms - last_change_ms &gt;= commit_delay_ms</span></span>
<span class="line"><span>    and now_ms - last_save_ms &gt;= minimum_save_interval_ms</span></span></code></pre></div><p>保存完成后的状态：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dirty = 0</span></span>
<span class="line"><span>last_save_ms = now_ms</span></span>
<span class="line"><span>save_count = save_count + 1</span></span></code></pre></div><h2 id="仿真观察" tabindex="-1">仿真观察 <a class="header-anchor" href="#仿真观察" aria-label="Permalink to &quot;仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_parameter_save_scheduler.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>默认生成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_parameter_save_scheduler.png</span></span></code></pre></div><p>图中包含三组曲线：<code>dirty flag</code>、<code>write pulse</code>、<code>NVM save pulse</code> 和 <code>save_count</code>。参数框写明 <code>commit_delay_ms=50</code>、<code>minimum_save_interval_ms=100</code>、写入时间点和保存时间点。</p><p>观察重点：</p><ul><li>0 ms 写入后 <code>dirty</code> 置 1，但不立刻保存。</li><li>20 ms 再次写入，<code>last_change_ms</code> 被刷新。</li><li>80 ms 距离最近一次写入已超过 50 ms，因此触发一次保存。</li><li>保存后 <code>dirty</code> 清零，<code>save_count</code> 变成 1。</li></ul><h2 id="固件落地" tabindex="-1">固件落地 <a class="header-anchor" href="#固件落地" aria-label="Permalink to &quot;固件落地&quot;">​</a></h2><ul><li><code>UpsParameterSaveScheduler</code>：保存触发状态。</li><li><code>dirty</code>：有参数未保存。</li><li><code>last_change_ms</code>：最近一次参数变化时间。</li><li><code>last_save_ms</code>：最近一次成功保存时间。</li><li><code>save_count</code>：教学统计，用来确认保存次数。</li><li><code>UpsParameterSaveScheduler_Init()</code>：初始化调度器。</li><li><code>UpsParameterSaveScheduler_MarkDirty()</code>：参数被接受写入后置脏。</li><li><code>UpsParameterSaveScheduler_ShouldSave()</code>：根据当前时间、延时提交和最小保存间隔判断是否保存。</li><li><code>UpsParameterSaveScheduler_OnSaved()</code>：保存成功后清脏并更新时间。</li></ul><p>真实工程还会考虑 Flash 扇区、双备份、掉电窗口、保存失败重试、磨损均衡和安全状态限制。本课只训练通用阅读路径。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>错误理解：参数一写入就必须马上保存。<br> 正确理解：很多场景应先置脏，再合并保存。</li><li>错误理解：只要加延时提交就足够。<br> 正确理解：还需要最小保存间隔，避免频繁保存。</li><li>错误理解：保存触发策略就是公司真实 Flash 策略。<br> 正确理解：本课不包含公司内部保存策略，只讲可迁移的通用结构。</li></ul><h2 id="一个仿真任务" tabindex="-1">一个仿真任务 <a class="header-anchor" href="#一个仿真任务" aria-label="Permalink to &quot;一个仿真任务&quot;">​</a></h2><p>先运行 <code>python simulations\\python\\ups_parameter_save_scheduler.py --no-open</code>，再打开 <code>simulations/results/ups_parameter_save_scheduler.png</code>。在图上标出：</p><ul><li>哪两个时刻是参数写入。</li><li>哪个时刻真正发生 NVM 保存。</li><li>保存后 <code>dirty</code> 为什么变成 0。</li><li>为什么保存次数是 1，不是 2。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能解释脏标志、延时提交和最小保存间隔分别解决什么问题。</li><li>能根据公式判断 40 ms 为什么不保存、80 ms 为什么保存。</li><li>能运行仿真并看到 <code>parameter writes: 2</code>、<code>nvm saves: 1</code>、<code>dirty cleared after save: True</code>。</li><li>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>parameter_save_scheduler</code> 输出。</li><li>能基于 <code>parameter_save_scheduler.c -&gt; UpsParameterSaveScheduler_ShouldSave()</code> 准备导师问题。</li></ul><h2 id="复盘问题" tabindex="-1">复盘问题 <a class="header-anchor" href="#复盘问题" aria-label="Permalink to &quot;复盘问题&quot;">​</a></h2><ul><li>为什么 0 ms 写入后不能马上把 <code>dirty</code> 清掉？</li><li>为什么 20 ms 再次写入会推迟保存时机？</li><li>如果通信连续改 5 个参数，保存触发策略应该关注“写入次数”还是“最终一致的参数快照”？</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><ul><li>我用 <code>simulations/results/ups_parameter_save_scheduler.png</code> 看到 0 ms 和 20 ms 两次写入只合并成 80 ms 一次保存。真实工程阅读时，通常从哪个函数看“参数写入”和“保存触发”的边界？</li><li>我用 <code>parameter_save_scheduler.c -&gt; UpsParameterSaveScheduler_ShouldSave()</code> 只检查 dirty、延时提交和最小保存间隔。真实工程里还会不会受系统模式、故障状态或掉电检测影响？</li><li>我不会记录公司内部保存策略，只想确认阅读顺序：应先看参数写入入口、保存调度入口，还是 NVM 驱动回调？</li></ul>`,41)])])}const m=a(t,[["render",r]]);export{u as __pageData,m as default};
